use tokio_stream::{self as stream, StreamExt};

#[tokio::main]
async fn main() {
    // Create a stream from an iterator
    let mut s = stream::iter(vec![1, 2, 3, 4, 5]);

    // Consume with while let
    while let Some(value) = s.next().await {
        println!("Got: {}", value);
    }
}

use tokio_stream::{self as stream, StreamExt};

#[tokio::main]
async fn main() {
    let s = stream::iter(1..=20);

    let results: Vec<i32> = s
        .filter(|x| *x % 2 == 0)    // keep even numbers
        .map(|x| x * x)              // square them
        .take(5)                      // take first 5
        .collect()
        .await;

    println!("{:?}", results);  // [4, 16, 36, 64, 100]
}

use tokio::sync::mpsc;
use tokio_stream::wrappers::ReceiverStream;
use tokio_stream::StreamExt;

#[tokio::main]
async fn main() {
    let (tx, rx) = mpsc::channel(32);

    tokio::spawn(async move {
        for i in 0..5 {
            tx.send(i).await.unwrap();
        }
    });

    let mut stream = ReceiverStream::new(rx);
    while let Some(value) = stream.next().await {
        println!("Received: {}", value);
    }
}

use tokio::time::{interval, Duration};
use tokio_stream::wrappers::IntervalStream;
use tokio_stream::StreamExt;

#[tokio::main]
async fn main() {
    let interval = interval(Duration::from_millis(500));
    let mut stream = IntervalStream::new(interval).take(5);

    while let Some(instant) = stream.next().await {
        println!("Tick at {:?}", instant);
    }
}
